// admin-retention.js — Retention drafts approval queue
// Reads retention_messages drafts (status='draft') generated by the
// nlp-retention pipeline and lets the admin review, edit, and approve.
// Approved rows are picked up by the (future) sender cron via Phase 3.

let retentionDrafts = [];
let currentRetentionFilter = 'draft';
let currentRetentionId = null;

const RETENTION_STATUS_LABEL = {
    draft: 'טיוטה', approved: 'אושר', rejected: 'נדחה',
    sent: 'נשלח', opted_out: 'הסרה', failed: 'נכשל'
};
const RETENTION_STATUS_CLASS = {
    draft: 'status-new', approved: 'status-approved', rejected: 'status-rejected',
    sent: 'status-contacted', opted_out: 'status-rejected', failed: 'status-rejected'
};
const RETENTION_WHY_LABEL = {
    career: 'קריירה',
    relationships: 'זוגיות',
    confidence: 'ביטחון עצמי',
    health: 'בריאות',
    'self-growth': 'צמיחה אישית'
};

function retentionWhyLabel(cat) {
    if (!cat) return '-';
    return RETENTION_WHY_LABEL[cat] || cat;
}

// Date grouping by generated_at (the shared groupByDate uses created_at).
function groupRetentionByDate(items) {
    const groups = { 'היום': [], 'אתמול': [], 'ישן יותר': [] };
    items.forEach(item => {
        const d = new Date(item.generated_at).toDateString();
        const today = new Date().toDateString();
        const yesterday = new Date(Date.now() - 86400000).toDateString();
        if (d === today) groups['היום'].push(item);
        else if (d === yesterday) groups['אתמול'].push(item);
        else groups['ישן יותר'].push(item);
    });
    return groups;
}

async function loadRetention() {
    const { data, error } = await db
        .from('retention_messages')
        .select('*')
        .order('generated_at', { ascending: false });
    if (error) {
        console.warn('loadRetention failed:', error);
        retentionDrafts = [];
    } else {
        retentionDrafts = data || [];
    }
    const draftsCount = retentionDrafts.filter(r => r.status === 'draft').length;
    setText('retention-count', draftsCount);
    setText('retention-stat-draft', draftsCount);
    setText('retention-stat-approved', retentionDrafts.filter(r => r.status === 'approved').length);
    setText('retention-stat-sent', retentionDrafts.filter(r => r.status === 'sent').length);
    setText('retention-stat-rejected', retentionDrafts.filter(r => r.status === 'rejected').length);
    renderRetention();
}

function filterRetention(filter) {
    currentRetentionFilter = filter;
    document.querySelectorAll('#retention-view .tab').forEach(t => t.classList.remove('active'));
    if (event && event.currentTarget) event.currentTarget.classList.add('active');
    renderRetention();
}

function renderRetention() {
    const search = document.getElementById('retention-search')?.value?.toLowerCase() || '';
    let filtered = retentionDrafts;
    if (currentRetentionFilter !== 'all') {
        filtered = filtered.filter(r => r.status === currentRetentionFilter);
    }
    if (search) {
        filtered = filtered.filter(r =>
            (r.full_name || '').toLowerCase().includes(search) ||
            (r.phone || '').includes(search)
        );
    }

    const tbody = document.getElementById('retention-table');
    if (!tbody) return;
    resetSelectAll('select-all-retention');
    updateBulkBarFor('retention');

    if (filtered.length === 0) {
        tbody.innerHTML = '<tr><td colspan="8" class="empty-state"><i class="fa-solid fa-bell-slash"></i><br>אין טיוטות במצב זה</td></tr>';
        return;
    }

    const groups = groupRetentionByDate(filtered);
    let html = '';
    for (const [group, items] of Object.entries(groups)) {
        if (items.length === 0) continue;
        html += `<tr class="date-group-row"><td colspan="8"><i class="fa-solid ${dateGroupIcons[group]}"></i> ${group} (${items.length})</td></tr>`;
        html += items.map(r => {
            const isDraft = r.status === 'draft';
            const rowStyle = isDraft ? 'style="background:rgba(212,175,55,0.05);"' : '';
            const messagePreview = (r.message_text || '').slice(0, 80) + ((r.message_text || '').length > 80 ? '…' : '');
            const phoneAnchor = r.phone ? `<a href="tel:${r.phone}" style="color:var(--info);text-decoration:none;" onclick="event.stopPropagation()">${r.phone}</a>` : '-';
            const lessonCell = r.next_lesson_index
                ? `<span style="font-weight:600;">#${r.next_lesson_index}</span> ${escapeHtml(r.next_lesson_title || '')}`
                : '-';
            const inactivityCell = r.days_inactive_at_send != null
                ? `<span style="color:var(--text-secondary);">${r.days_inactive_at_send} ימים</span>`
                : '-';
            return `
                <tr ${rowStyle} style="cursor:pointer;" onclick="openRetentionModal('${r.id}')">
                    <td class="lead-checkbox" onclick="event.stopPropagation()"><input type="checkbox" value="${r.id}" data-status="${r.status}" onchange="updateBulkBarFor('retention')"></td>
                    <td><strong>${escapeHtml(r.full_name || '-')}</strong><br><span style="font-size:0.78rem;color:var(--text-secondary);">${escapeHtml(messagePreview)}</span></td>
                    <td>${phoneAnchor}</td>
                    <td>${escapeHtml(retentionWhyLabel(r.why_category))}</td>
                    <td style="max-width:220px;">${lessonCell}</td>
                    <td>${inactivityCell}</td>
                    <td><span class="status-badge ${RETENTION_STATUS_CLASS[r.status] || 'status-new'}">${RETENTION_STATUS_LABEL[r.status] || r.status}</span></td>
                    <td class="action-btns" onclick="event.stopPropagation()">
                        <div class="row-menu" id="menu-r-${r.id}">
                            <button class="row-menu-btn" onclick="toggleRowMenu('menu-r-${r.id}')">⋮</button>
                            <div class="row-menu-dropdown">
                                <button class="row-menu-item" onclick="openRetentionModal('${r.id}');closeAllMenus()"><i class="fa-solid fa-eye"></i> צפייה ועריכה</button>
                                ${isDraft ? `<button class="row-menu-item" onclick="approveRetention('${r.id}');closeAllMenus()"><i class="fa-solid fa-check" style="color:var(--success);"></i> אישור מהיר</button>` : ''}
                                ${isDraft ? `<button class="row-menu-item danger" onclick="rejectRetention('${r.id}');closeAllMenus()"><i class="fa-solid fa-xmark"></i> דחייה</button>` : ''}
                                ${r.phone ? `<button class="row-menu-item" onclick="window.open('https://wa.me/${r.phone.replace(/^0/,'972')}','_blank');closeAllMenus()"><i class="fa-brands fa-whatsapp" style="color:#25D366;"></i> WhatsApp</button>` : ''}
                            </div>
                        </div>
                    </td>
                </tr>
            `;
        }).join('');
    }
    tbody.innerHTML = html;
}

function toggleSelectAllRetention() { toggleSelectAllFor('retention'); }

function openRetentionModal(id) {
    const r = retentionDrafts.find(x => x.id === id);
    if (!r) return;
    currentRetentionId = id;

    const isDraft = r.status === 'draft';

    const visionBox = r.vision_one_year ? `
        <div style="background:linear-gradient(135deg,rgba(0,59,70,0.08),rgba(212,175,55,0.05));border-right:4px solid var(--gold);border-radius:10px;padding:1rem 1.2rem;margin:1rem 0;">
            <div style="font-size:0.78rem;color:var(--text-secondary);margin-bottom:0.4rem;letter-spacing:0.04em;">החזון של התלמיד לעוד שנה</div>
            <div style="font-size:1rem;line-height:1.55;color:var(--text-primary);font-weight:500;">"${escapeHtml(r.vision_one_year)}"</div>
        </div>` : '';

    const whyBox = r.why_nlp ? `
        <div style="background:var(--bg);border-radius:10px;padding:1rem 1.2rem;margin:1rem 0;">
            <div style="font-size:0.78rem;color:var(--text-secondary);margin-bottom:0.4rem;letter-spacing:0.04em;">למה NLP — התשובה שלו בשאלון</div>
            <div style="font-size:0.95rem;line-height:1.55;color:var(--text-primary);">${escapeHtml(r.why_nlp)}</div>
        </div>` : '';

    const detailRow = (label, val) => val ? `
        <div style="display:flex;justify-content:space-between;padding:0.4rem 0;border-bottom:1px dashed var(--border);">
            <span style="color:var(--text-secondary);font-size:0.85rem;">${label}</span>
            <span style="font-weight:600;font-size:0.9rem;">${escapeHtml(String(val))}</span>
        </div>` : '';

    const statusBadge = `<span class="status-badge ${RETENTION_STATUS_CLASS[r.status] || 'status-new'}">${RETENTION_STATUS_LABEL[r.status] || r.status}</span>`;
    const phoneAnchor = r.phone ? `<a href="tel:${r.phone}" style="color:var(--info);text-decoration:none;">${r.phone}</a>` : '-';

    const html = `
        <div style="padding:1.5rem;">
            <!-- Student card -->
            <div style="background:var(--bg);border-radius:12px;padding:1.2rem;margin-bottom:1rem;border-right:4px solid var(--deep-petrol);">
                <div style="display:flex;align-items:center;gap:1rem;margin-bottom:0.8rem;">
                    <div style="width:50px;height:50px;border-radius:50%;background:linear-gradient(135deg,var(--gold),#c9a227);display:flex;align-items:center;justify-content:center;color:white;font-size:1.3rem;font-weight:700;">${(r.full_name || '?')[0]}</div>
                    <div style="flex:1;">
                        <h3 style="margin:0;color:var(--text-primary);font-size:1.1rem;">${escapeHtml(r.full_name || 'ללא שם')}</h3>
                        <div style="margin-top:4px;display:flex;gap:0.4rem;align-items:center;flex-wrap:wrap;">
                            ${statusBadge}
                            <span style="font-size:0.8rem;color:var(--text-secondary);">${formatDateTime(r.generated_at)}</span>
                        </div>
                    </div>
                </div>
                ${detailRow('טלפון', r.phone)}
                ${detailRow('סיבה (קטגוריה)', retentionWhyLabel(r.why_category))}
                ${detailRow('שיעור הבא', r.next_lesson_index ? `#${r.next_lesson_index} — ${r.next_lesson_title || ''}` : null)}
                ${detailRow('ימים שלא התקדם', r.days_inactive_at_send)}
                ${detailRow('שעת שליחה מומלצת', r.recommended_send_hour ? `${r.recommended_send_hour}:00` : null)}
                ${r.approved_at ? detailRow('אושר ב', formatDateTime(r.approved_at)) : ''}
                ${r.sent_at ? detailRow('נשלח ב', formatDateTime(r.sent_at)) : ''}
                ${r.send_error ? detailRow('שגיאה', r.send_error) : ''}
            </div>

            ${visionBox}
            ${whyBox}

            <!-- Editable message -->
            <div style="margin-top:1rem;">
                <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:0.4rem;">
                    <label style="font-weight:600;color:var(--text-primary);">ההודעה לוואטסאפ</label>
                    <span id="retention-char-count" style="font-size:0.78rem;color:var(--text-secondary);"></span>
                </div>
                <textarea id="retention-message-text" ${isDraft ? '' : 'readonly'} style="width:100%;min-height:200px;border-radius:8px;border:1px solid var(--border);padding:0.9rem;font-family:inherit;font-size:0.95rem;line-height:1.6;resize:vertical;background:var(--bg);${isDraft ? '' : 'opacity:0.85;'}" oninput="updateRetentionCharCount()">${escapeHtml(r.message_text || '')}</textarea>
                ${isDraft ? `<div style="margin-top:0.4rem;font-size:0.78rem;color:var(--text-secondary);">שינויים שתעשה לטקסט יישמרו ברגע שתלחץ "אשר ושלח לתור". המדיניות: 60-120 מילים.</div>` : ''}
            </div>
        </div>
    `;

    document.getElementById('retention-modal-title').textContent = `סקירת טיוטת שימור — ${r.full_name || ''}`.trim();
    document.getElementById('retention-modal-body').innerHTML = html;

    const approveBtn = document.getElementById('retention-btn-approve');
    const rejectBtn = document.getElementById('retention-btn-reject');
    const saveBtn = document.getElementById('retention-btn-save');
    if (isDraft) {
        approveBtn.style.display = '';
        rejectBtn.style.display = '';
        if (saveBtn) saveBtn.style.display = '';
    } else {
        approveBtn.style.display = 'none';
        rejectBtn.style.display = 'none';
        if (saveBtn) saveBtn.style.display = 'none';
    }

    const waBtn = document.getElementById('retention-btn-whatsapp');
    if (r.phone) {
        const waPhone = (r.phone || '').replace(/^0/, '972').replace(/[^0-9]/g, '');
        waBtn.href = `https://wa.me/${waPhone}`;
        waBtn.style.display = '';
    } else {
        waBtn.style.display = 'none';
    }

    openModal('retention-modal');
    updateRetentionCharCount();
}

function updateRetentionCharCount() {
    const ta = document.getElementById('retention-message-text');
    const counter = document.getElementById('retention-char-count');
    if (!ta || !counter) return;
    const text = ta.value || '';
    const words = text.trim() ? text.trim().split(/\s+/).length : 0;
    const inRange = words >= 50 && words <= 150;
    counter.textContent = `${words} מילים · ${text.length} תווים`;
    counter.style.color = inRange ? 'var(--success)' : 'var(--warning, #d97706)';
}

async function approveRetentionFromModal() {
    if (!currentRetentionId) return;
    const ta = document.getElementById('retention-message-text');
    const editedText = ta ? ta.value.trim() : '';
    if (!editedText) { showToast('ההודעה ריקה', 'error'); return; }
    await approveRetention(currentRetentionId, editedText);
    closeModal('retention-modal');
}

async function saveRetentionEdit() {
    if (!currentRetentionId) return;
    const row = retentionDrafts.find(x => x.id === currentRetentionId);
    if (!row) return;
    if (row.status !== 'draft') { showToast('ניתן לערוך רק טיוטות', 'warning'); return; }

    const ta = document.getElementById('retention-message-text');
    const editedText = ta ? ta.value.trim() : '';
    if (!editedText) { showToast('ההודעה ריקה', 'error'); return; }

    if (editedText === row.message_text) {
        showToast('אין שינויים לשמירה', 'info');
        return;
    }

    const btn = document.getElementById('retention-btn-save');
    if (btn) { btn.disabled = true; btn.style.opacity = '0.6'; }

    const { error } = await db.from('retention_messages')
        .update({ message_text: editedText })
        .eq('id', currentRetentionId);

    if (btn) { btn.disabled = false; btn.style.opacity = ''; }

    if (error) { showToast('שגיאה בשמירה: ' + (error.message || ''), 'error'); return; }

    row.message_text = editedText;  // keep local state in sync so "no changes" check works on next click
    showToast('השינויים נשמרו. עדיין לא אושר.', 'success');
    loadRetention();
}

async function approveRetention(id, editedText) {
    const row = retentionDrafts.find(x => x.id === id);
    if (!row) return;
    if (row.status !== 'draft') { showToast('לא ניתן לאשר טיוטה במצב הזה', 'warning'); return; }

    const { data: { session } } = await db.auth.getSession();
    const update = {
        status: 'approved',
        approved_at: new Date().toISOString(),
        approved_by: session?.user?.id || null
    };
    if (editedText && editedText !== row.message_text) {
        update.message_text = editedText;
    }
    const { error } = await db.from('retention_messages').update(update).eq('id', id);
    if (error) { showToast('שגיאה באישור: ' + (error.message || ''), 'error'); return; }
    showToast('הטיוטה אושרה ותיכנס לתור שליחה', 'success');
    loadRetention();
}

async function rejectRetentionFromModal() {
    if (!currentRetentionId) return;
    if (!confirm('לדחות את הטיוטה הזו? היא תישמר בהיסטוריה אך לא תישלח.')) return;
    await rejectRetention(currentRetentionId);
    closeModal('retention-modal');
}

async function rejectRetention(id) {
    const row = retentionDrafts.find(x => x.id === id);
    if (!row) return;
    if (row.status !== 'draft') { showToast('לא ניתן לדחות טיוטה במצב הזה', 'warning'); return; }
    if (!confirm(`לדחות את הטיוטה של ${row.full_name || ''}?`)) return;

    const { error } = await db.from('retention_messages')
        .update({ status: 'rejected' })
        .eq('id', id);
    if (error) { showToast('שגיאה בדחייה', 'error'); return; }
    showToast('הטיוטה נדחתה', 'success');
    loadRetention();
}

async function bulkApproveRetention() {
    const selected = Array.from(document.querySelectorAll('#retention-table .lead-checkbox input[type="checkbox"]:checked'));
    const draftIds = selected
        .filter(cb => cb.dataset.status === 'draft')
        .map(cb => cb.value);
    if (draftIds.length === 0) { showToast('לא נבחרו טיוטות לאישור', 'warning'); return; }
    if (!confirm(`לאשר ${draftIds.length} טיוטות בבת אחת?`)) return;

    const { data: { session } } = await db.auth.getSession();
    const update = {
        status: 'approved',
        approved_at: new Date().toISOString(),
        approved_by: session?.user?.id || null
    };
    const { error } = await db.from('retention_messages')
        .update(update)
        .in('id', draftIds);
    if (error) { showToast('שגיאה באישור גורף: ' + (error.message || ''), 'error'); return; }
    showToast(`${draftIds.length} טיוטות אושרו`, 'success');
    loadRetention();
}

function exportRetentionCSV() {
    if (retentionDrafts.length === 0) { showToast('אין נתונים לייצוא', 'warning'); return; }
    const headers = ['שם', 'טלפון', 'סטטוס', 'סיבה', 'שיעור הבא', 'ימי חוסר פעילות', 'הודעה', 'נוצר ב', 'אושר ב', 'נשלח ב'];
    const rows = retentionDrafts.map(r => [
        r.full_name || '',
        r.phone || '',
        RETENTION_STATUS_LABEL[r.status] || r.status || '',
        retentionWhyLabel(r.why_category),
        r.next_lesson_index ? `#${r.next_lesson_index} ${r.next_lesson_title || ''}` : '',
        r.days_inactive_at_send != null ? r.days_inactive_at_send : '',
        (r.message_text || '').replace(/\n/g, ' '),
        formatDateTime(r.generated_at),
        formatDateTime(r.approved_at),
        formatDateTime(r.sent_at)
    ]);
    const bom = '﻿';
    const csv = bom + [headers, ...rows].map(row => row.map(c => `"${(c+'').replace(/"/g, '""')}"`).join(',')).join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `retention_drafts_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    showToast('הקובץ הורד בהצלחה!', 'success');
}

function toggleRetentionInfo() {
    const box = document.getElementById('retention-info-box');
    if (!box) return;
    box.classList.toggle('open');
}

// ---------------------------------------------------------------------------
// Manual scan + generate trigger — calls retention-run Edge Function.
// Limit: 30 students per call (Edge Function timeout safety). When more
// inactive students remain, the response includes remaining > 0 and we
// nudge the admin to click again.
// ---------------------------------------------------------------------------

async function runRetentionScan() {
    const btn = document.getElementById('retention-run-btn');
    const status = document.getElementById('retention-run-status');
    if (!btn || !status) return;

    btn.disabled = true;
    btn.style.opacity = '0.7';
    btn.style.cursor = 'wait';
    btn.innerHTML = '<i class="fa-solid fa-circle-notch fa-spin"></i> סורק ומייצר טיוטות...';
    status.textContent = 'הפעולה לוקחת בין 30 שניות לדקה וחצי, תלוי בכמה תלמידים יש. אל תסגור את הטאב.';
    status.style.color = 'var(--text-secondary)';

    try {
        const { data: { session } } = await db.auth.getSession();
        if (!session) {
            showToast('פג תוקף ההתחברות, התחבר מחדש', 'error');
            resetRetentionRunButton();
            return;
        }

        const url = window.SUPABASE_CONFIG.url + '/functions/v1/retention-run';
        const res = await fetch(url, {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${session.access_token}`,
                'Content-Type': 'application/json',
                'apikey': window.SUPABASE_CONFIG.anonKey,
            },
            body: JSON.stringify({ limit: 30 }),
        });
        const result = await res.json();

        if (!res.ok) {
            const msg = result?.error || `שגיאה (HTTP ${res.status})`;
            showToast('סריקה נכשלה: ' + msg, 'error');
            status.textContent = 'הסריקה נכשלה. נסה שוב.';
            status.style.color = 'var(--danger, #f85149)';
            resetRetentionRunButton();
            return;
        }

        const { scanned, processed, inserted, skipped, failed, remaining } = result;
        const parts = [];
        parts.push(`נמצאו ${scanned} תלמידים לא-פעילים`);
        if (processed > 0) parts.push(`עיבדנו ${processed}`);
        if (inserted > 0) parts.push(`${inserted} טיוטות חדשות`);
        if (skipped > 0) parts.push(`${skipped} דילוגים (כבר קיים)`);
        if (failed > 0) parts.push(`${failed} כשלונות`);
        if (remaining > 0) parts.push(`נותרו ${remaining} — לחץ שוב כדי להמשיך`);
        status.textContent = parts.join(' · ');
        status.style.color = inserted > 0 ? 'var(--success, #22c55e)' : 'var(--text-secondary)';

        if (inserted > 0) {
            showToast(`${inserted} טיוטות חדשות מוכנות לסקירה`, 'success');
        } else if (scanned === 0) {
            showToast('אין תלמידים לא-פעילים כרגע', 'success');
        } else if (skipped > 0 && inserted === 0) {
            showToast('כל הטיוטות כבר קיימות — אין מה להוסיף', 'success');
        }

        await loadRetention();
    } catch (err) {
        console.error('retention-run error:', err);
        showToast('שגיאה בקריאה לפונקציה: ' + (err?.message || ''), 'error');
        status.textContent = 'שגיאה. בדוק את הקונסול.';
        status.style.color = 'var(--danger, #f85149)';
    } finally {
        resetRetentionRunButton();
    }
}

function resetRetentionRunButton() {
    const btn = document.getElementById('retention-run-btn');
    if (!btn) return;
    btn.disabled = false;
    btn.style.opacity = '';
    btn.style.cursor = '';
    btn.innerHTML = '<i class="fa-solid fa-wand-magic-sparkles"></i> סרוק נוטשים → ייצר טיוטות';
}
